import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { Item, Location, Movement } from '../../core/models';

/**
 * Movements audit log (manager only). Every recorded movement with the acting
 * user, item, locations and quantity, newest first. The `?itemId=`, `?from=`
 * and `?to=` filters are bound to query params so a filtered view is shareable.
 */
@Component({
  selector: 'app-movements-log',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './movements-log.component.html',
  styleUrl: './movements-log.component.css',
})
export class MovementsLogComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly itemFilter = signal('');
  readonly from = signal('');
  readonly to = signal('');

  readonly items = signal<Item[]>([
    { id: 'i1', sku: 'SKU-1001', name: 'Steel Bolt M6', unit: 'pcs', reorderAt: 100 },
    { id: 'i2', sku: 'SKU-1002', name: 'Copper Wire 2mm', unit: 'm', reorderAt: 200 },
    { id: 'i3', sku: 'SKU-1003', name: 'PVC Pipe 20mm', unit: 'pcs', reorderAt: 50 },
    { id: 'i6', sku: 'SKU-1006', name: 'Rubber Gasket 50mm', unit: 'pcs', reorderAt: 80 },
  ]);

  readonly locations = signal<Location[]>([
    { id: 'l1', name: 'Main Warehouse', zone: 'A' },
    { id: 'l2', name: 'Storefront', zone: 'B' },
    { id: 'l3', name: 'Overflow Depot', zone: 'C' },
  ]);

  readonly movements = signal<Movement[]>([
    { id: 'm1', type: 'IN', itemId: 'i1', toLocId: 'l1', qty: 200, userId: 'u1',
      user: { id: 'u1', email: 'clerk@demo', name: 'Demo Clerk', role: 'clerk' },
      note: 'PO-4821', createdAt: '2026-07-12T09:15:00Z' },
    { id: 'm2', type: 'TRANSFER', itemId: 'i1', fromLocId: 'l1', toLocId: 'l2', qty: 80, userId: 'u2',
      user: { id: 'u2', email: 'manager@demo', name: 'Demo Manager', role: 'manager' },
      note: 'Restock storefront', createdAt: '2026-07-11T16:40:00Z' },
    { id: 'm3', type: 'OUT', itemId: 'i3', fromLocId: 'l2', qty: 38, userId: 'u1',
      user: { id: 'u1', email: 'clerk@demo', name: 'Demo Clerk', role: 'clerk' },
      note: 'Job #221', createdAt: '2026-07-11T11:05:00Z' },
    { id: 'm4', type: 'IN', itemId: 'i2', toLocId: 'l1', qty: 85, userId: 'u2',
      user: { id: 'u2', email: 'manager@demo', name: 'Demo Manager', role: 'manager' },
      note: null, createdAt: '2026-07-10T08:30:00Z' },
    { id: 'm5', type: 'OUT', itemId: 'i6', fromLocId: 'l3', qty: 80, userId: 'u1',
      user: { id: 'u1', email: 'clerk@demo', name: 'Demo Clerk', role: 'clerk' },
      note: 'Damaged batch', createdAt: '2026-07-09T14:20:00Z' },
  ]);

  readonly filtered = computed<Movement[]>(() => {
    const item = this.itemFilter();
    const from = this.from();
    const to = this.to();
    return this.movements().filter((m) => {
      if (item && m.itemId !== item) return false;
      const day = (m.createdAt ?? '').slice(0, 10);
      if (from && day < from) return false;
      if (to && day > to) return false;
      return true;
    });
  });

  constructor(
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.route.queryParamMap.subscribe((p) => {
      this.itemFilter.set(p.get('itemId') ?? '');
      this.from.set(p.get('from') ?? '');
      this.to.set(p.get('to') ?? '');
    });
  }

  applyFilters(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: {
        itemId: this.itemFilter() || null,
        from: this.from() || null,
        to: this.to() || null,
      },
      queryParamsHandling: 'merge',
    });
  }

  clear(): void {
    this.itemFilter.set('');
    this.from.set('');
    this.to.set('');
    this.applyFilters();
  }

  itemLabel(id: string): string {
    const it = this.items().find((i) => i.id === id);
    return it ? `${it.sku} — ${it.name}` : id;
  }

  locationName(id?: string | null): string {
    if (!id) return '—';
    return this.locations().find((l) => l.id === id)?.name ?? id;
  }

  badgeClass(type: Movement['type']): string {
    if (type === 'IN') return 'badge-ok';
    if (type === 'OUT') return 'badge-danger';
    return 'badge-info';
  }
}
